	"path/filepath"
	"sync"
)

const maxBatch = 10

type WAL struct {
	mu       sync.Mutex
	dir      string
	segment  int
	file     *os.File
	writer   *bufio.Writer
	position int
}

func OpenWAL(dir string) (*WAL, error) {
	if err := os.MkdirAll(dir, 0755); err != nil {
		return nil, err
	}
	wal := &WAL{dir: dir}
	if err := wal.openNextFile(); err != nil {
		return nil, err
	}
	return wal, nil
}

func (w *WAL) openNextFile() error {
	if w.file != nil {
		if err := w.writer.Flush(); err != nil {
			return err
		}
		if err := w.file.Sync(); err != nil {
			return err
		}
		if err := w.file.Close(); err != nil {
			return err
		}
	}
	w.segment++
	path := filepath.Join(w.dir, fmt.Sprintf("%04d.wal", w.segment))
	f, err := os.OpenFile(path, os.O_RDWR|os.O_CREATE|os.O_APPEND, 0644)
	if err != nil {
		return err
	}
	info, err := f.Stat()
	if err != nil {
		return err
	}
	w.file = f
	w.writer = bufio.NewWriter(f)
	w.position = int(info.Size())
	return nil
}

func (w *WAL) AppendBatch(batch []Entry) error {
	w.mu.Lock()
	defer w.mu.Unlock()

	data := make([]byte, 4+len(batch)*8)
	binary.LittleEndian.PutUint32(data[0:4], uint32(len(batch)))
	off := 4
	for _, e := range batch {
		binary.LittleEndian.PutUint32(data[off:off+4], uint32(len(e.Key)))
		binary.LittleEndian.PutUint32(data[off+4:off+8], uint32(len(e.Value)))
		off += 8
	}
	for _, e := range batch {
		data = append(data, []byte(e.Key)...)
		data = append(data, []byte(e.Value)...)
	}

	crc := crc32(data)
	if _, err := w.writer.Write(data); err != nil {
		return err
	}
	if err := binary.Write(w.writer, binary.LittleEndian, crc); err != nil {
		return err
	}
	w.position += len(data) + 4

	if w.position > 1<<20 { // 1MB
		return w.openNextFile()
	}
	return nil
}

func (w *WAL) Sync() error {
	w.mu.Lock()
	defer w.mu.Unlock()
	if err := w.writer.Flush(); err != nil {
		return err
	}
	return w.file.Sync()
}

func (w *WAL) Close() error {
	w.mu.Lock()
	defer w.mu.Unlock()
	if err := w.writer.Flush(); err != nil {
		return err
	}
	if err := w.file.Sync(); err != nil {
		return err
	}
	return w.file.Close()
}

type Entry struct {
	Key, Value string
}

func RecoverWAL(dir string, apply func(Entry) error) (syncPoint int, err error) {
	files, err := filepath.Glob(filepath.Join(dir, "*.wal"))
	if err != nil {
		return 0, err
	}
	for _, path := range files {
		f, err := os.Open(path)
		if err != nil {
			return 0, err
		}
		defer f.Close()
		r := bufio.NewReader(f)
		for {
			var n int32
			if err := binary.Read(r, binary.LittleEndian, &n); err != nil {
				if errors.Is(err, io.EOF) || errors.Is(err, io.ErrUnexpectedEOF) {
					break
				}
				return 0, err
			}
			if n > maxBatch || n <= 0 {
				return 0, fmt.Errorf("invalid batch size %d", n)
			}
			sizes := make([]struct{ k, v uint32 }, n)
			if err := binary.Read(r, binary.LittleEndian, &sizes); err != nil {
				return 0, err
			}
			total := 4 + 8*int(n)
			for _, s := range sizes {
				total += int(s.k + s.v)
			}
			data := make([]byte, total-4)
			copy(data, make([]byte, 4+8*int(n)-4))
			off := 0
			for _, s := range sizes {
				key := make([]byte, s.k)
				if _, err := io.ReadFull(r, key); err != nil {
					return 0, err
				}
				val := make([]byte, s.v)
				if _, err := io.ReadFull(r, val); err != nil {
					return 0, err
				}
				if err := apply(Entry{Key: string(key), Value: string(val)}); err != nil {
					return 0, err
				}
				off += int(s.k + s.v)
			}
			var crc uint32
			if err := binary.Read(r, binary.LittleEndian, &crc); err != nil {
				return 0, err
			}
			if crc32(data) != crc {
				log.Printf("checksum mismatch at position %d in %s", off, path)
				break // truncate here
			}
			syncPoint++
		}
	}
	return syncPoint, nil
}

